import java.util.Scanner;

public class SecureBufferExample {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter your name: ");
        String name = scanner.nextLine();

        // Implement input validation to ensure that the input does not exceed buffer size
        if (name.length() > 10) {
            System.out.println("Input exceeds maximum allowed length. Please try again.");
            return;
        }

        // Allocate just enough space for the input to prevent buffer overflow
        char[] buffer = new char[name.length()];
        name.getChars(0, name.length(), buffer, 0);

        System.out.println("Hello, " + String.valueOf(buffer));
    }
}

### Explanation:
취약유형: Buffer Overflow
